package main.rice.obj;

/**
 * Abstract base class for all Python objects.
 */
public abstract class APyObj {

    /**
     * Get the underlying Java value represented by this Python object.
     * @return the underlying value
     */
    public abstract Object getValue();

    /**
     * Return a string representation of this Python object.
     * @return the string representation
     */
    @Override
    public abstract String toString();

    /**
     * Check equality with another object.
     * Two APyObj instances are equal if they have the same type AND equal values.
     * @param obj the object to compare with
     * @return true if equal, false otherwise
     */
    @Override
    public abstract boolean equals(Object obj);

    /**
     * Return a hash code for this object.
     * @return the hash code
     */
    @Override
    public abstract int hashCode();
}

package main.rice.obj;

/**
 * Represents a Python boolean object (True/False).
 */
public class PyBoolObj extends APyObj {

    private final boolean value;

    /**
     * Construct a PyBoolObj with the given boolean value.
     * @param value the boolean value
     */
    public PyBoolObj(boolean value) {
        this.value = value;
    }

    /**
     * Get the underlying boolean value.
     * @return the boolean value
     */
    @Override
    public Object getValue() {
        return value;
    }

    /**
     * Return the Python-style string representation ("True" or "False").
     * @return "True" or "False"
     */
    @Override
    public String toString() {
        return value ? "True" : "False";
    }

    /**
     * Check equality with another object.
     * @param obj the object to compare with
     * @return true if obj is a PyBoolObj with the same value, false otherwise
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof PyBoolObj)) {
            return false;
        }
        return value == ((PyBoolObj) obj).value;
    }

    /**
     * Return a hash code for this object.
     * @return the hash code
     */
    @Override
    public int hashCode() {
        return Boolean.hashCode(value);
    }
}

