import java.util.*;

/**
 * Represents a Python string object.
 * Internally stores a list of PyCharObj objects.
 */
public class PyStringObj extends AIterablePyObj {

    private final List<PyCharObj> value;
    private final String originalString;

    /**
     * Construct a PyStringObj with the given string.
     * @param str the string value
     */
    public PyStringObj(String str) {
        this.originalString = str;
        this.value = new ArrayList<>();
        for (char c : str.toCharArray()) {
            value.add(new PyCharObj(c));
        }
    }

    /**
     * Get the underlying list of PyCharObj values.
     * @return the list of PyCharObj
     */
    @Override
    public Object getValue() {
        return value;
    }

    /**
     * Return the Python-style string representation (surrounded by single quotes).
     * @return the string representation
     */
    @Override
    public String toString() {
        return "'" + originalString + "'";
    }

    /**
     * Check equality with another object.
     * @param obj the object to compare with
     * @return true if obj is a PyStringObj with the same value, false otherwise
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof PyStringObj)) {
            return false;
        }
        return originalString.equals(((PyStringObj) obj).originalString);
    }

    /**
     * Return a hash code for this object.
     * @return the hash code
     */
    @Override
    public int hashCode() {
        return originalString.hashCode();
    }
}

