     * Get the underlying list of items.
     * @return the list of items
     */
    @Override
    public Object getValue() {
        return value;
    }

    /**
     * Return the Python-style string representation (elements in square brackets).
     * @return the string representation
     */
    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("[");
        for (int i = 0; i < value.size(); i++) {
            if (i > 0) {
                sb.append(", ");
            }
            sb.append(value.get(i).toString());
        }
        sb.append("]");
        return sb.toString();
    }

    /**
     * Check equality with another object.
     * @param obj the object to compare with
     * @return true if obj is a PyListObj with the same value, false otherwise
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof PyListObj)) {
            return false;
        }
        PyListObj<?> other = (PyListObj<?>) obj;
        return value.equals(other.value);
    }

    /**
     * Return a hash code for this object.
     * @return the hash code
     */
    @Override
    public int hashCode() {
        return value.hashCode();
    }
}

